import xml.etree.ElementTree as ET
tree = ET.parse('/work/output/artifacts/skill-bpmn-transform-group-by/TransformGroupByDemo.bpmn')
root = tree.getroot()

ns = {
    'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
    'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
    'uipath': 'http://uipath.org/schema/bpmn',
}

proc = root.find('bpmn:process', ns)

# Collect all flow-element ids
all_ids = set()
for el in proc.iter():
    eid = el.get('id')
    if eid:
        all_ids.add(eid)

# Check sequence flows resolve
errors = []
for sf in proc.findall('bpmn:sequenceFlow', ns):
    src = sf.get('sourceRef')
    tgt = sf.get('targetRef')
    if src not in all_ids:
        errors.append(f'sourceRef {src!r} not found')
    if tgt not in all_ids:
        errors.append(f'targetRef {tgt!r} not found')

# Check shapes/edges in diagram
diagram = root.find('bpmndi:BPMNDiagram', ns)
plane = diagram.find('bpmndi:BPMNPlane', ns)
shaped = {s.get('bpmnElement') for s in plane.findall('bpmndi:BPMNShape', ns)}
edged  = {e.get('bpmnElement') for e in plane.findall('bpmndi:BPMNEdge', ns)}

# Every flow node should have a shape
for el in proc:
    eid = el.get('id')
    tag = el.tag.split('}')[1] if '}' in el.tag else el.tag
    if tag in ('startEvent','endEvent','scriptTask','exclusiveGateway','parallelGateway'):
        if eid not in shaped:
            errors.append(f'node {eid!r} ({tag}) has no BPMNShape')

# Every sequence flow should have an edge
for sf in proc.findall('bpmn:sequenceFlow', ns):
    sfid = sf.get('id')
    if sfid not in edged:
        errors.append(f'sequenceFlow {sfid!r} has no BPMNEdge')

# Check uipath namespace present
uipath_ns = 'http://uipath.org/schema/bpmn'
found_uipath = any(uipath_ns in str(root.attrib))
if not found_uipath:
    errors.append('uipath namespace not declared on root')

# Check scriptVersion v3 and scriptFormat
for st in proc.findall('bpmn:scriptTask', ns):
    sf = st.get('scriptFormat')
    if sf != 'JavaScript':
        errors.append(f'scriptTask {st.get(\"id\")!r} scriptFormat is {sf!r}, expected JavaScript')
    sv = st.find('.//{http://uipath.org/schema/bpmn}scriptVersion')
    if sv is None or sv.get('value') != 'v3':
        errors.append(f'scriptTask {st.get(\"id\")!r} missing scriptVersion v3')
    script = st.find('bpmn:script', ns)
    if script is None or not (script.text or '').strip():
        errors.append(f'scriptTask {st.get(\"id\")!r} has no script body')

if errors:
    for e in errors:
        print('ERROR:', e)
    raise SystemExit(1)

print('VALID - all structural checks passed')
print(f'  nodes with shapes: {sorted(shaped)}')
print(f'  flows with edges:  {sorted(edged)}')
"

python3 -c "
import xml.etree.ElementTree as ET
tree = ET.parse('/work/output/artifacts/skill-bpmn-transform-group-by/TransformGroupByDemo.bpmn')
root = tree.getroot()

ns = {
    'bpmn': 'http://www.omg.org/spec/BPMN/20100524/MODEL',
    'bpmndi': 'http://www.omg.org/spec/BPMN/20100524/DI',
    'uipath': 'http://uipath.org/schema/bpmn',
}

proc = root.find('bpmn:process', ns)
all_ids = set()
for el in proc.iter():
    eid = el.get('id')
    if eid:
        all_ids.add(eid)

errors = []

# Sequence flows resolve
for sf in proc.findall('bpmn:sequenceFlow', ns):
    src = sf.get('sourceRef')
    tgt = sf.get('targetRef')
    if src not in all_ids:
        errors.append('sourceRef ' + repr(src) + ' not found')
    if tgt not in all_ids:
        errors.append('targetRef ' + repr(tgt) + ' not found')

# Diagram shapes/edges
diagram = root.find('bpmndi:BPMNDiagram', ns)
plane = diagram.find('bpmndi:BPMNPlane', ns)
shaped = {s.get('bpmnElement') for s in plane.findall('bpmndi:BPMNShape', ns)}
edged  = {e.get('bpmnElement') for e in plane.findall('bpmndi:BPMNEdge', ns)}

for el in proc:
    eid = el.get('id')
    tag = el.tag.split('}')[1] if '}' in el.tag else el.tag
    if tag in ('startEvent','endEvent','scriptTask','exclusiveGateway','parallelGateway'):
        if eid not in shaped:
            errors.append('node ' + repr(eid) + ' (' + tag + ') has no BPMNShape')

for sf in proc.findall('bpmn:sequenceFlow', ns):
    sfid = sf.get('id')
    if sfid not in edged:
        errors.append('sequenceFlow ' + repr(sfid) + ' has no BPMNEdge')

# uipath namespace
raw = ET.tostring(root, encoding='unicode')[:500]
if 'http://uipath.org/schema/bpmn' not in raw:
    errors.append('uipath namespace not declared on root')

# scriptTask checks
for st in proc.findall('bpmn:scriptTask', ns):
    if st.get('scriptFormat') != 'JavaScript':
        errors.append('scriptTask scriptFormat != JavaScript')
    sv = st.find('.//{http://uipath.org/schema/bpmn}scriptVersion')
    if sv is None or sv.get('value') != 'v3':
        errors.append('scriptTask missing scriptVersion v3')
    script = st.find('bpmn:script', ns)
    if script is None or not (script.text or '').strip():
        errors.append('scriptTask has no script body')
    mapping = st.find('.//{http://uipath.org/schema/bpmn}mapping')
    if mapping is None:
        errors.append('scriptTask missing uipath:mapping')
    mtype = st.find('.//{http://uipath.org/schema/bpmn}type')
    if mtype is None or mtype.get('value') != 'BPMN.ScriptTask':
        errors.append('scriptTask mapping type != BPMN.ScriptTask')

if errors:
    for e in errors:
        print('ERROR:', e)
    raise SystemExit(1)

print('VALID - all structural checks passed')
print('  nodes with shapes:', sorted(shaped))
print('  flows with edges: ', sorted(edged))
"
